      <div class="form-grid pos-setting-values"><label>Tax rate (%)<input type="number" min="0" max="30" step="0.001" name="pos_tax_rate" value="<?= e((string) setting('pos_tax_rate','0')) ?>"></label><label>Maximum manual discount (%)<input type="number" min="0" max="100" step="1" name="pos_max_discount_percent" value="<?= (int) setting('pos_max_discount_percent',20) ?>"></label></div>
