    <section class="admin-panel settings-section"><div><span class="step-label">Reporting</span><h2>Business time and location</h2><p>Sales ranges and charts use this timezone. Existing order timestamps are never rewritten.</p></div><div class="form-grid"><label>Business city<input name="business_city" value="<?= e((string) setting('business_city','Long Island, NY')) ?>" placeholder="Long Island, NY"></label><label>Reporting timezone<select name="report_timezone"><?php foreach(['America/New_York'=>'Eastern Time','America/Chicago'=>'Central Time','America/Denver'=>'Mountain Time','America/Los_Angeles'=>'Pacific Time','America/Phoenix'=>'Arizona Time','America/Anchorage'=>'Alaska Time','Pacific/Honolulu'=>'Hawaii Time'] as $zone=>$label): ?><option value="<?= e($zone) ?>" <?= setting('report_timezone','America/New_York')===$zone?'selected':'' ?>><?= e($label) ?> — <?= e($zone) ?></option><?php endforeach; ?></select></label></div></section>

    <section class="admin-panel settings-section"><div><span class="step-label">Business details</span><h2>Store information</h2></div><div class="form-grid"><label>Store name<input name="store_name" value="<?= e(setting('store_name')) ?>"></label><label>Status<select name="store_status"><option value="open" <?= setting('store_status')==='open'?'selected':'' ?>>Open</option><option value="paused" <?= setting('store_status')==='paused'?'selected':'' ?>>Paused</option><option value="closed" <?= setting('store_status')==='closed'?'selected':'' ?>>Closed</option></select></label><label>Phone<input name="store_phone" value="<?= e(setting('store_phone')) ?>"></label><label>Email<input type="email" name="store_email" value="<?= e(setting('store_email')) ?>"></label><label class="full">Tagline<input name="store_tagline" value="<?= e(setting('store_tagline')) ?>"></label><label class="full">Announcement<input name="announcement" value="<?= e(setting('announcement')) ?>"></label><label>Hours<input name="hours" value="<?= e(setting('hours')) ?>"></label><label>License number<input name="license_number" value="<?= e(setting('license_number')) ?>"></label><label class="full">Required warning<textarea name="required_warning" rows="3"><?= e(setting('required_warning')) ?></textarea></label></div></section>

